// Importing React Router components for navigation
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';

// Importing custom components and pages
import Navbar from './components/Navbar';
import Home from './pages/Home';
import AdminPanel from './components/AdminPanel';
import Cart from './pages/Cart';
import Checkout from './pages/Checkout';
import ProductDetails from './pages/ProductDetails';
import StoreLocator from './pages/StoreLocator';
impo

// Importing global CSS styles
import './App.css';

// Main application component and routing structure
function App() {
  return (
    <Router>
      <Navbar />
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/admin" element={<AdminPanel />} />
        <Route path="/cart" element={<Cart />} />
        <Route path="/checkout" element={<Checkout />} />
        <Route path="/product/:id" element={<ProductDetails />} /> {/* Product details route */}
        <Route path="/store-locator" element={<StoreLocator />} /> {/* Store locator route */}
      </Routes>
    </Router>
  );
}

export default App;
